  ('locality-6e2f88c7-moex-00143', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-112-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '下列何者非屬效力未定之法律行為？', '["自己代理", "無權處分", "善意受讓", "無權代理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "316", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
